-- PostgreSQL demo seed data
-- Run after database/postgres/schema.sql.

BEGIN;










-- Active tournament progress demo: R1 and R2 completed, R3 published and waiting.
UPDATE "races"
SET
  "status" = CASE "id"
    WHEN 'r_001' THEN 'completed'
    WHEN 'r_002' THEN 'completed'
    WHEN 'r_003' THEN 'published'
    ELSE "status"
  END,
  "participants" = CASE "id" WHEN 'r_001' THEN 10 WHEN 'r_002' THEN 10 WHEN 'r_003' THEN 10 ELSE "participants" END,
  "ownerConfirmed" = CASE "id" WHEN 'r_001' THEN 10 WHEN 'r_002' THEN 10 WHEN 'r_003' THEN 10 ELSE "ownerConfirmed" END,
  "jockeyConfirmed" = CASE "id" WHEN 'r_001' THEN 10 WHEN 'r_002' THEN 10 WHEN 'r_003' THEN 10 ELSE "jockeyConfirmed" END,
  "resultStatus" = CASE "id" WHEN 'r_001' THEN 'official' WHEN 'r_002' THEN 'official' WHEN 'r_003' THEN 'draft' ELSE "resultStatus" END,
  "awardsPublished" = CASE "id" WHEN 'r_001' THEN TRUE WHEN 'r_002' THEN TRUE WHEN 'r_003' THEN FALSE ELSE "awardsPublished" END
WHERE "id" IN ('r_001', 'r_002', 'r_003');

UPDATE "raceEntries" AS "entry"
SET
  "lane" = "values"."lane",
  "handicap" = "values"."handicap",
  "ratingSnapshot" = "values"."rating",
  "ownerConfirmed" = TRUE,
  "jockeyConfirmed" = TRUE,
  "preRaceStatus" = 'ready',
  "resultStatus" = 'official',
  "position" = "values"."position",
  "finishTime" = "values"."finishTime",
  "notes" = "values"."notes",
  "violationNotes" = ''
FROM (VALUES
  ('re_001', 1, 5.0, 86.8, 1, '01:31.24', 'R1 official result - 10 pts'),
  ('re_002', 2, 5.0, 84.0, 2, '01:32.80', 'R1 official result - 7 pts'),
  ('re_003', 3, 5.0, 85.4, 3, '01:34.10', 'R1 official result - 5 pts'),
  ('re_004', 4, 5.0, 86.9, 4, '01:35.64', 'R1 official result - 3 pts'),
  ('re_005', 5, 5.0, 83.7, 5, '01:37.02', 'R1 official result - 2 pts'),
  ('re_006', 6, 5.0, 85.7, 6, '01:38.40', 'R1 official result - 1 pt'),
  ('re_007', 7, 5.0, 85.5, 7, '01:39.65', 'R1 official result - 0 pts'),
  ('re_008', 8, 5.0, 84.4, 8, '01:40.21', 'R1 official result - 0 pts'),
  ('re_009', 9, 5.0, 86.0, 9, '01:41.36', 'R1 official result - 0 pts'),
  ('re_010', 10, 5.0, 85.8, 10, '01:42.08', 'R1 official result - 0 pts')
) AS "values"("id", "lane", "handicap", "rating", "position", "finishTime", "notes")
WHERE "entry"."id" = "values"."id";

ON CONFLICT ("id") DO UPDATE SET
  "lane" = EXCLUDED."lane",
  "handicap" = EXCLUDED."handicap",
  "ratingSnapshot" = EXCLUDED."ratingSnapshot",
  "ownerConfirmed" = TRUE,
  "jockeyConfirmed" = TRUE,
  "preRaceStatus" = 'ready',
  "resultStatus" = 'official',
  "position" = EXCLUDED."position",
  "finishTime" = EXCLUDED."finishTime",
  "notes" = EXCLUDED."notes";

ON CONFLICT ("id") DO UPDATE SET
  "lane" = EXCLUDED."lane",
  "handicap" = EXCLUDED."handicap",
  "ratingSnapshot" = EXCLUDED."ratingSnapshot",
  "ownerConfirmed" = TRUE,
  "jockeyConfirmed" = TRUE,
  "preRaceStatus" = 'ready',
  "resultStatus" = 'draft',
  "position" = NULL,
  "finishTime" = NULL,
  "notes" = EXCLUDED."notes";



-- Completed tournament demo data

COMMIT;
